import { attachElementToHead, getBrandCode } from "../../../src/lib/global-navigation/helpers";
import { globalBaseConfig } from "../../../src/config/global-base-config";

describe("attachElementToHead", () => {
  beforeEach(() => {
    document.head.innerHTML = "";
  });
  test("attachElementToHead with a script positives", () => {
    attachElementToHead({ elemType: "script", link: "https://a.b.com" });
    let tag = document.getElementsByTagName("script")[0];
    expect(tag).toBeTruthy();
    expect(tag.src).toBe("https://a.b.com/");
  });
  test("attachElementToHead with a CSS link positives", () => {
    attachElementToHead({ elemType: "link", link: "https://a.b.com" });
    let tag = document.getElementsByTagName("link")[0];
    expect(tag).toBeTruthy();
    expect(tag.href).toBe("https://a.b.com/");
  });
  test("attachElementToHead with a meta tag positives", () => {
    attachElementToHead({
      elemType: "meta",
      property: "canonical",
      rel: "canonical",
      content: "bob"
    });
    let tag = document.getElementsByTagName("meta")[0];
    expect(tag).toBeTruthy();
    expect(tag.getAttribute("property")).toBe("canonical");
    expect(tag.rel).toBe("canonical");
    expect(tag.content).toBe("bob");
  });
  test("attachElementToHead with a different meta tag positives", () => {
    attachElementToHead({ elemType: "meta", name: "referrer", content: "bob" });
    let tag = document.getElementsByTagName("meta")[0];
    expect(tag).toBeTruthy();
    expect(tag.name).toBe("referrer");
    expect(tag.content).toBe("bob");
  });
  test("attachElementToHead with a style tag", () => {
    attachElementToHead({ elemType: "style", innerText: "hello" });
    let tag = document.getElementsByTagName("style")[0];
    expect(tag).toBeTruthy();
    expect(tag.innerText).toBe("hello");
  });
  test("attachElementToHead with a title tag", () => {
    attachElementToHead({ elemType: "title", innerText: "Document title" });
    let tag = document.getElementsByTagName("title")[0];
    expect(tag).toBeTruthy();
    expect(tag.innerText).toBe("Document title");
  });
});

describe("getBrandCode", () => {
  test("Gets the default brand name no AO data is given", () => {
    expect(getBrandCode({}, "bob")).toBe("bob");
  });
  test("Gets maeu if defaults are passed", () => {
    expect(getBrandCode(globalBaseConfig.AO, globalBaseConfig.DEFAULT_BRAND_CODE)).toBe("maeu");
  });
  test("Gets undefined if no default is passed the url is unknown", () => {
    global.jsdom.reconfigure({
      url: "https://www.example.com/"
    });
    expect(getBrandCode(globalBaseConfig.AO)).toBe(undefined);
  });
  test("Gets maeu if no default is passed and the URL matches Maersk", () => {
    global.jsdom.reconfigure({
      url: "https://www.maersk.com/"
    });
    expect(getBrandCode(globalBaseConfig.AO)).toBe("maeu");
  });

  const brandCodeMap = [
    { url: "https://www.sealandmaersk.com/", brand: "seau" },
    { url: "https://my.seagoline.sg.com/", brand: "sejj" },
    { url: "https://my.sealand.com/", brand: "seau" },
    { url: "https://my.mcc.co/", brand: "mcpu" },
    { url: "https://www.maerskline.com.cn/", brand: "maeu" },
    { url: "https://demo.maerskline.com/", brand: "maeu" },
    { url: "https://myt.maerskline.com/", brand: "maeu" },
    { url: "https://myt.sealand.com/", brand: "seau" },
    { url: "https://stage.sealand.com/", brand: "seau" },
    { url: "https://demo.maersklinelimited.com/", brand: "maei" },
    { url: "https://mybeta-stage.maerskline.com/", brand: "maeu" },
    { url: "https://mybeta-stage.sealand.com/", brand: "seau" },
    { url: "https://mybeta-stage.sealandmaersk.com/", brand: "seau" },
    { url: "https://www.hamburgsud.com/", brand: "sudu" }
  ];
  brandCodeMap.forEach((bcMap) => {
    test("Gets the right brand code for " + bcMap.url, () => {
      global.jsdom.reconfigure({ url: bcMap.url });
      expect(getBrandCode(globalBaseConfig.AO)).toBe(bcMap.brand);
    });
  });
});
